class PIIMasker:
    """Utility to mask PII data in log outputs."""
    
    @staticmethod
    def mask_email(email: str) -> str:
        if not email or '@' not in email:
            return '***'
        local, domain = email.rsplit('@', 1)
        masked_local = local[0] + '***' if len(local) > 0 else '***'
        return f"{masked_local}@{domain}"
    
    @staticmethod
    def mask_phone(phone: str) -> str:
        if not phone:
            return '***'
        digits = re.sub(r'\D', '', phone)
        if len(digits) >= 4:
            return '***' + digits[-4:]
        return '***'
    
    @staticmethod
    def mask_address(address: str) -> str:
        if not address:
            return '***'
        return address[:3] + '***'
    
    @staticmethod
    def mask_user_data(user_data: dict) -> dict:
        """Return a masked copy of user data suitable for logging."""
        masked = {}
        for key, value in user_data.items():
            if key in ('email',):
                masked[key] = PIIMasker.mask_email(str(value))
            elif key in ('phone', 'phone_number'):
                masked[key] = PIIMasker.mask_phone(str(value))
            elif key in ('address', 'street_address', 'home_address'):
                masked[key] = PIIMasker.mask_address(str(value))
            elif key in ('ssn', 'social_security_number', 'credit_card', 'password'):
                masked[key] = '***REDACTED***'
            else:
                masked[key] = value
        return masked


class MessageEncryptor:
    """Encrypts message payloads containing PII before publishing to SQS."""
    
    def __init__(self, encryption_key: str = None):
        if encryption_key is None:
            encryption_key = os.environ.get('SQS_MESSAGE_ENCRYPTION_KEY')
        if not encryption_key:
            raise ValueError(
                "Encryption key must be provided via parameter or "
                "SQS_MESSAGE_ENCRYPTION_KEY environment variable. "
                "PII data must not be sent unencrypted."
            )
        kdf = PBKDF2HMAC(
            algorithm=hashes.SHA256(),
            length=32,
            salt=b'sqs-pii-publisher-salt-v1',
            iterations=480000,
        )
        key = base64.urlsafe_b64encode(kdf.derive(encryption_key.encode()))
        self._fernet = Fernet(key)
    
    def encrypt(self, plaintext: str) -> str:
        """Encrypt a string and return base64-encoded ciphertext."""
        return self._fernet.encrypt(plaintext.encode()).decode()
    
    def decrypt(self, ciphertext: str) -> str:
        """Decrypt base64-encoded ciphertext and return plaintext string."""
        return self._fernet.decrypt(ciphertext.encode()).decode()


